import { format, formatDistanceToNow } from 'date-fns';

/**
 * Formats a date string in a user-friendly format
 * @param {string|Date} dateString - The date to format
 * @param {Object} options - Formatting options
 * @param {boolean} options.withRelativeTime - Whether to include relative time (e.g., "2 days ago")
 * @param {boolean} options.includeTime - Whether to include the time
 * @returns {string} Formatted date string
 */
const formatDate = (dateString, options = {}) => {
  if (!dateString) return '';
  
  const date = new Date(dateString);
  if (isNaN(date.getTime())) return 'Invalid date';
  
  const { includeTime = false, includeRelativeTime = false } = options;
  
  // For relative time
  if (includeRelativeTime) {
    const now = new Date();
    const diffInSeconds = Math.floor((now - date) / 1000);
    
    if (diffInSeconds < 60) {
      return 'just now';
    }
    
    const diffInMinutes = Math.floor(diffInSeconds / 60);
    if (diffInMinutes < 60) {
      return `${diffInMinutes} ${diffInMinutes === 1 ? 'minute' : 'minutes'} ago`;
    }
    
    const diffInHours = Math.floor(diffInMinutes / 60);
    if (diffInHours < 24) {
      return `${diffInHours} ${diffInHours === 1 ? 'hour' : 'hours'} ago`;
    }
    
    const diffInDays = Math.floor(diffInHours / 24);
    if (diffInDays < 7) {
      return `${diffInDays} ${diffInDays === 1 ? 'day' : 'days'} ago`;
    }
    
    const diffInWeeks = Math.floor(diffInDays / 7);
    if (diffInWeeks < 4) {
      return `${diffInWeeks} ${diffInWeeks === 1 ? 'week' : 'weeks'} ago`;
    }
    
    const diffInMonths = Math.floor(diffInDays / 30);
    if (diffInMonths < 12) {
      return `${diffInMonths} ${diffInMonths === 1 ? 'month' : 'months'} ago`;
    }
    
    const diffInYears = Math.floor(diffInDays / 365);
    return `${diffInYears} ${diffInYears === 1 ? 'year' : 'years'} ago`;
  }
  
  // Standard date formatting
  const day = date.getDate().toString().padStart(2, '0');
  const month = (date.getMonth() + 1).toString().padStart(2, '0');
  const year = date.getFullYear();
  
  let formattedDate = `${day}/${month}/${year}`;
  
  if (includeTime) {
    const hours = date.getHours().toString().padStart(2, '0');
    const minutes = date.getMinutes().toString().padStart(2, '0');
    formattedDate += ` ${hours}:${minutes}`;
  }
  
  return formattedDate;
};

/**
 * Format a date with both date and time
 * @param {string|Date} date - Date to format
 * @returns {string} Formatted date and time
 */
const formatDateTime = (date) => {
  if (!date) return 'N/A';
  
  try {
    const dateObj = new Date(date);
    return format(dateObj, 'PPp'); // Mar 15, 2023, 3:45 PM
  } catch (error) {
    console.error('Error formatting date and time:', error);
    return 'Invalid date';
  }
};

/**
 * Format a date as relative time (e.g., "5 days ago")
 * @param {string|Date} date - Date to format
 * @returns {string} Relative time
 */
const formatRelativeTime = (date) => {
  if (!date) return 'N/A';
  
  try {
    const dateObj = new Date(date);
    return formatDistanceToNow(dateObj, { addSuffix: true });
  } catch (error) {
    console.error('Error formatting relative time:', error);
    return 'Invalid date';
  }
};

/**
 * Format a date for display in application forms
 * @param {string|Date} date - Date to format
 * @returns {string} Date formatted as YYYY-MM-DD for input[type="date"]
 */
const formatForDateInput = (date) => {
  if (!date) return '';
  
  try {
    const dateObj = new Date(date);
    return format(dateObj, 'yyyy-MM-dd');
  } catch (error) {
    console.error('Error formatting date for input:', error);
    return '';
  }
};

/**
 * Get a formatted date range display
 * @param {string|Date} startDate - Start date
 * @param {string|Date} endDate - End date
 * @returns {string} Formatted date range
 */
const formatDateRange = (startDate, endDate) => {
  if (!startDate || !endDate) return 'N/A';
  
  try {
    const startDateObj = new Date(startDate);
    const endDateObj = new Date(endDate);
    return `${format(startDateObj, 'PP')} - ${format(endDateObj, 'PP')}`;
  } catch (error) {
    console.error('Error formatting date range:', error);
    return 'Invalid date range';
  }
};

export default formatDate;

export {
  formatDateTime,
  formatRelativeTime,
  formatForDateInput,
  formatDateRange
};
